#include<string>
#include<iostream>
#include<algorithm>
using namespace std;

int dp[205][205], m[205], t[205], v[205];
string ans[205][205];

int main(){
	int n, M, T;
	cin >> M >> T >> n;
	for(int i = 1; i <= n; i++)
		cin >> m[i] >> t[i] >> v[i];
	for(int i = 1; i <= n; i++)
		for(int j = M; j >= m[i]; j--)
			for(int k = T; k >= t[i]; k--)
				if(dp[j][k] < dp[j - m[i]][k - t[i]] + v[i] || dp[j][k] == dp[j - m[i]][k - t[i]] + v[i] && ans[j - m[i]][k - t[i]] + to_string(i) < ans[j][k])
				{
					dp[j][k] = dp[j - m[i]][k - t[i]] + v[i];
					ans[j][k] = ans[j - m[i]][k - t[i]] + to_string(i) + " ";
				}
	cout << dp[M][T] << endl;
	cout << ans[M][T];
	return 0;
}
